import{_ as e,o as i,c as l,aB as o}from"./chunks/framework.DThK36Ag.js";const a="data:image/svg+xml;base64,",r="/BattMo.jl/previews/PR145/assets/geometry_p4d_pouch.CjkrodlW.png",d="/BattMo.jl/previews/PR145/assets/geometry_p4d_cylindrical.BQAGK57B.png",y=JSON.parse('{"title":"Geometries","description":"","frontmatter":{},"headers":[],"relativePath":"manuals/user_guide/geometries.md","filePath":"manuals/user_guide/geometries.md","lastUpdated":null}'),s={name:"manuals/user_guide/geometries.md"};function n(c,t,g,h,u,I){return i(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="Geometries" tabindex="-1">Geometries <a class="header-anchor" href="#Geometries" aria-label="Permalink to &quot;Geometries {#Geometries}&quot;">​</a></h1><p>BattMo supports several battery-cell geometries through the <code>ModelFramework</code> setting. These geometries determine how the electrochemical model is distributed in space, which grids are constructed, and which component-wise outputs are available.</p><p>The currently supported geometry families are:</p><ul><li><p><code>P2D</code></p></li><li><p><code>P4D Pouch</code></p></li><li><p><code>P4D Cylindrical</code></p></li></ul><h2 id="Overview" tabindex="-1">Overview <a class="header-anchor" href="#Overview" aria-label="Permalink to &quot;Overview {#Overview}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Model framework</th><th style="text-align:right;">Cell type</th><th style="text-align:right;">Spatial representation</th><th style="text-align:right;">Typical use</th></tr></thead><tbody><tr><td style="text-align:right;"><code>P2D</code></td><td style="text-align:right;">Through-thickness cell model</td><td style="text-align:right;">1D across the stack, with radial particle diffusion</td><td style="text-align:right;">Fast cell-level studies, parameter sweeps, cycling analysis</td></tr><tr><td style="text-align:right;"><code>P4D Pouch</code></td><td style="text-align:right;">Pouch cell</td><td style="text-align:right;">3D current-collector / electrode geometry combined with particle diffusion</td><td style="text-align:right;">Tab placement effects, current distribution, pouch thermal/electrical nonuniformity</td></tr><tr><td style="text-align:right;"><code>P4D Cylindrical</code></td><td style="text-align:right;">Cylindrical / jelly-roll cell</td><td style="text-align:right;">Cylindrical wound-cell geometry combined with particle diffusion</td><td style="text-align:right;">Radial and axial heterogeneity in cylindrical cells</td></tr></tbody></table><p>In all three cases, BattMo uses a pseudo-dimensional formulation:</p><ul><li><p>the electrolyte and solid-phase transport are resolved on the cell geometry</p></li><li><p>diffusion inside active-material particles is resolved on a particle-radius coordinate</p></li><li><p>component coupling is handled automatically in the assembled multiphysics model</p></li></ul><h2 id="P2D" tabindex="-1">P2D <a class="header-anchor" href="#P2D" aria-label="Permalink to &quot;P2D {#P2D}&quot;">​</a></h2><p><code>P2D</code> is the classical Doyle-Fuller-Newman style through-thickness model. The cell is represented as a one-dimensional stack:</p><ul><li><p>negative electrode</p></li><li><p>separator</p></li><li><p>positive electrode</p></li></ul><p>If current collectors are enabled, the stack also includes:</p><ul><li><p>negative current collector</p></li><li><p>positive current collector</p></li></ul><p>This is the most efficient option and is usually the right starting point when:</p><ul><li><p>studying voltage response, concentration profiles, or degradation behavior</p></li><li><p>calibrating parameters</p></li><li><p>running large parameter sweeps</p></li><li><p>current-collector in-plane effects are not important</p></li></ul><p>For <code>P2D</code>, BattMo provides:</p><ul><li><p>a global through-cell position, <code>output.states[&quot;Cell&quot;][&quot;Position&quot;]</code></p></li><li><p>component-wise positions, such as <code>output.states[&quot;NegativeElectrode&quot;][&quot;ActiveMaterial&quot;][&quot;Position&quot;]</code></p></li></ul><h3 id="Main-Cell-Parameters" tabindex="-1">Main Cell Parameters <a class="header-anchor" href="#Main-Cell-Parameters" aria-label="Permalink to &quot;Main Cell Parameters {#Main-Cell-Parameters}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Input path</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;Coating&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Negative electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;Coating&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Positive electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;Separator&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Separator thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Negative current collector thickness, when current collectors are enabled.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Positive current collector thickness, when current collectors are enabled.</td></tr></tbody></table><h3 id="Main-Simulation-Settings" tabindex="-1">Main Simulation Settings <a class="header-anchor" href="#Main-Simulation-Settings" aria-label="Permalink to &quot;Main Simulation Settings {#Main-Simulation-Settings}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Setting</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>NegativeElectrodeCoatingGridPoints</code></td><td style="text-align:right;">Number of cells through the negative electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCoatingGridPoints</code></td><td style="text-align:right;">Number of cells through the positive electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>SeparatorGridPoints</code></td><td style="text-align:right;">Number of cells through the separator thickness.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeParticleGridPoints</code></td><td style="text-align:right;">Radial resolution inside negative active-material particles.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeParticleGridPoints</code></td><td style="text-align:right;">Radial resolution inside positive active-material particles.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCurrentCollectorGridPoints</code></td><td style="text-align:right;">Number of cells through the negative current collector thickness.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCurrentCollectorGridPoints</code></td><td style="text-align:right;">Number of cells through the positive current collector thickness.</td></tr></tbody></table><p><img src="'+a+'" alt=""></p><h2 id="P4D-Pouch" tabindex="-1">P4D Pouch <a class="header-anchor" href="#P4D-Pouch" aria-label="Permalink to &quot;P4D Pouch {#P4D-Pouch}&quot;">​</a></h2><p><code>P4D Pouch</code> resolves the cell in a pouch-cell geometry. The model keeps the pseudo-dimensional electrochemistry, but the cell components are placed on a multi-dimensional spatial grid so that in-plane current and potential variations can be captured.</p><p>This geometry is useful when:</p><ul><li><p>tab placement matters</p></li><li><p>current collectors contribute significantly to the cell response</p></li><li><p>you want to visualize spatially varying potentials, concentrations, or currents</p></li><li><p>nonuniform utilization across the pouch is important</p></li></ul><p>The main components represented are:</p><ul><li><p>negative current collector</p></li><li><p>negative electrode active material / coating</p></li><li><p>separator</p></li><li><p>electrolyte</p></li><li><p>positive electrode active material / coating</p></li><li><p>positive current collector</p></li></ul><p>BattMo provides component-wise mesh positions for these domains in the output, for example:</p><ul><li><p><code>output.states[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Position&quot;]</code></p></li><li><p><code>output.states[&quot;PositiveElectrode&quot;][&quot;ActiveMaterial&quot;][&quot;Position&quot;]</code></p></li><li><p><code>output.states[&quot;Electrolyte&quot;][&quot;Position&quot;]</code></p></li></ul><h3 id="Main-Cell-Parameters-2" tabindex="-1">Main Cell Parameters <a class="header-anchor" href="#Main-Cell-Parameters-2" aria-label="Permalink to &quot;Main Cell Parameters {#Main-Cell-Parameters-2}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Input path</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;ElectrodeWidth&quot;]</code></td><td style="text-align:right;">Physical electrode width of the pouch cell.</td></tr><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;ElectrodeLength&quot;]</code></td><td style="text-align:right;">Physical electrode length of the pouch cell.</td></tr><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;TabWidth&quot;]</code></td><td style="text-align:right;">Width of the pouch tabs.</td></tr><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;TabLength&quot;]</code></td><td style="text-align:right;">Length of the pouch tabs.</td></tr><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;TabsOnSameSide&quot;]</code></td><td style="text-align:right;">Whether positive and negative tabs are placed on the same side of the pouch.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;TabPositionFraction&quot;]</code></td><td style="text-align:right;">Tab position along the negative current collector width, from <code>0</code> to <code>1</code>.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;CurrentCollector&quot;][&quot;TabPositionFraction&quot;]</code></td><td style="text-align:right;">Tab position along the positive current collector width, from <code>0</code> to <code>1</code>.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;Coating&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Negative electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;Coating&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Positive electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;Separator&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Separator thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Negative current collector thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Positive current collector thickness.</td></tr></tbody></table><h3 id="Main-Simulation-Settings-2" tabindex="-1">Main Simulation Settings <a class="header-anchor" href="#Main-Simulation-Settings-2" aria-label="Permalink to &quot;Main Simulation Settings {#Main-Simulation-Settings-2}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Setting</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>ElectrodeWidthGridPoints</code></td><td style="text-align:right;">In-plane grid resolution along pouch width.</td></tr><tr><td style="text-align:right;"><code>ElectrodeLengthGridPoints</code></td><td style="text-align:right;">In-plane grid resolution along pouch length.</td></tr><tr><td style="text-align:right;"><code>TabWidthGridPoints</code></td><td style="text-align:right;">In-plane resolution across the pouch tab width.</td></tr><tr><td style="text-align:right;"><code>TabLengthGridPoints</code></td><td style="text-align:right;">In-plane resolution along the pouch tab length.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCoatingGridPoints</code></td><td style="text-align:right;">Number of cells through the negative electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCoatingGridPoints</code></td><td style="text-align:right;">Number of cells through the positive electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>SeparatorGridPoints</code></td><td style="text-align:right;">Number of cells through the separator thickness.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeParticleGridPoints</code></td><td style="text-align:right;">Radial resolution inside negative active-material particles.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeParticleGridPoints</code></td><td style="text-align:right;">Radial resolution inside positive active-material particles.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCurrentCollectorGridPoints</code></td><td style="text-align:right;">Number of cells through the negative current collector thickness.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCurrentCollectorGridPoints</code></td><td style="text-align:right;">Number of cells through the positive current collector thickness.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCurrentCollectorTabWidthGridPoints</code></td><td style="text-align:right;">Resolution across the negative tab face.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCurrentCollectorTabLengthGridPoints</code></td><td style="text-align:right;">Resolution along the negative pouch-tab face length.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCurrentCollectorTabWidthGridPoints</code></td><td style="text-align:right;">Resolution across the positive tab face.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCurrentCollectorTabLengthGridPoints</code></td><td style="text-align:right;">Resolution along the positive pouch-tab face length.</td></tr></tbody></table><p><img src="'+r+'" alt=""></p><p>See also:</p><ul><li><a href="./../../examples/example_3D_pouch">3D Pouch example</a></li></ul><h2 id="P4D-Cylindrical" tabindex="-1">P4D Cylindrical <a class="header-anchor" href="#P4D-Cylindrical" aria-label="Permalink to &quot;P4D Cylindrical {#P4D-Cylindrical}&quot;">​</a></h2><p><code>P4D Cylindrical</code> targets cylindrical cells with a jelly-roll type internal structure. It extends the pseudo-dimensional electrochemistry to a cylindrical geometry so that spatial variations around the wound cell can be represented.</p><p>This geometry is useful when:</p><ul><li><p>modelling cylindrical commercial cells</p></li><li><p>studying radial and axial nonuniformities</p></li><li><p>investigating tab-driven current distribution</p></li><li><p>comparing simplified <code>P2D</code> behavior with a more spatially resolved cylindrical model</p></li></ul><p>As for the pouch case, outputs are provided component-wise for the resolved domains.</p><h3 id="Main-Cell-Parameters-3" tabindex="-1">Main Cell Parameters <a class="header-anchor" href="#Main-Cell-Parameters-3" aria-label="Permalink to &quot;Main Cell Parameters {#Main-Cell-Parameters-3}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Input path</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;InnerRadius&quot;]</code></td><td style="text-align:right;">Inner jelly-roll radius.</td></tr><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;OuterRadius&quot;]</code></td><td style="text-align:right;">Outer jelly-roll radius.</td></tr><tr><td style="text-align:right;"><code>[&quot;Cell&quot;][&quot;Height&quot;]</code></td><td style="text-align:right;">Axial height of the cylindrical cell.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;TabFractions&quot;]</code></td><td style="text-align:right;">Angular or spiral placement of one or more negative tabs as fractions of total spiral length.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;CurrentCollector&quot;][&quot;TabFractions&quot;]</code></td><td style="text-align:right;">Angular or spiral placement of one or more positive tabs as fractions of total spiral length.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;TabWidth&quot;]</code></td><td style="text-align:right;">Width of the negative current-collector tab.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;CurrentCollector&quot;][&quot;TabWidth&quot;]</code></td><td style="text-align:right;">Width of the positive current-collector tab.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;Coating&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Negative electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;Coating&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Positive electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;Separator&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Separator thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;NegativeElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Negative current collector thickness.</td></tr><tr><td style="text-align:right;"><code>[&quot;PositiveElectrode&quot;][&quot;CurrentCollector&quot;][&quot;Thickness&quot;]</code></td><td style="text-align:right;">Positive current collector thickness.</td></tr></tbody></table><h3 id="Main-Simulation-Settings-3" tabindex="-1">Main Simulation Settings <a class="header-anchor" href="#Main-Simulation-Settings-3" aria-label="Permalink to &quot;Main Simulation Settings {#Main-Simulation-Settings-3}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Setting</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>HeightGridPoints</code></td><td style="text-align:right;">Number of grid cells along the cylinder height.</td></tr><tr><td style="text-align:right;"><code>AngularGridPoints</code></td><td style="text-align:right;">Number of angular sectors used around the jelly roll.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCoatingGridPoints</code></td><td style="text-align:right;">Number of cells through the negative electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCoatingGridPoints</code></td><td style="text-align:right;">Number of cells through the positive electrode coating thickness.</td></tr><tr><td style="text-align:right;"><code>SeparatorGridPoints</code></td><td style="text-align:right;">Number of cells through the separator thickness.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeParticleGridPoints</code></td><td style="text-align:right;">Radial resolution inside negative active-material particles.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeParticleGridPoints</code></td><td style="text-align:right;">Radial resolution inside positive active-material particles.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCurrentCollectorGridPoints</code></td><td style="text-align:right;">Number of cells through the negative current collector thickness.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCurrentCollectorGridPoints</code></td><td style="text-align:right;">Number of cells through the positive current collector thickness.</td></tr><tr><td style="text-align:right;"><code>NegativeElectrodeCurrentCollectorTabWidthGridPoints</code></td><td style="text-align:right;">Resolution across the negative tab face.</td></tr><tr><td style="text-align:right;"><code>PositiveElectrodeCurrentCollectorTabWidthGridPoints</code></td><td style="text-align:right;">Resolution across the positive tab face.</td></tr></tbody></table><p><img src="'+d+`" alt=""></p><p>See also:</p><ul><li><a href="./../../examples/example_3D_cylindrical">3D cylindrical example</a></li></ul><h2 id="Choosing-A-Geometry" tabindex="-1">Choosing A Geometry <a class="header-anchor" href="#Choosing-A-Geometry" aria-label="Permalink to &quot;Choosing A Geometry {#Choosing-A-Geometry}&quot;">​</a></h2><p>As a rule of thumb:</p><ul><li><p>use <code>P2D</code> when speed and robust cell-scale trends are most important</p></li><li><p>use <code>P4D Pouch</code> for pouch cells with spatially resolved collector/electrode effects</p></li><li><p>use <code>P4D Cylindrical</code> for cylindrical cells where wound-cell geometry matters</p></li></ul><p>You select the geometry through the model settings:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_settings </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> load_model_settings</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(; from_default_set </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;p4d_pouch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> LithiumIonBattery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(; model_settings)</span></span></code></pre></div><p>or by setting:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_settings[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ModelFramework&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;P2D&quot;</span></span></code></pre></div><h2 id="Related-Pages" tabindex="-1">Related Pages <a class="header-anchor" href="#Related-Pages" aria-label="Permalink to &quot;Related Pages {#Related-Pages}&quot;">​</a></h2><ul><li><p><a href="./pxd_model">Lithium ion model</a></p></li><li><p><a href="./grid_params">Grid parameters</a></p></li><li><p><a href="./simulation_output">Simulation output</a></p></li></ul>`,58)])])}const m=e(s,[["render",n]]);export{y as __pageData,m as default};
